parameters.jsCode:
// Extract duplicate lead information
const duplicates = $input.item.json.result || [];
const newLead = $('Webhook: Check Duplicate').item.json;

const duplicateInfo = duplicates.map(dup => ({
  email: dup.payload.email,
  name: dup.payload.name,
  company: dup.payload.company,
  similarity: (dup.score * 100).toFixed(1),
  timestamp: dup.payload.timestamp,
  intent: dup.payload.intent,
  qualification_score: dup.payload.qualification_score
}));

return {
  json: {
    new_lead_email: newLead.email,
    new_lead_name: `${newLead.firstName} ${newLead.lastName}`,
    new_lead_company: newLead.company,
    duplicates: duplicateInfo,
    duplicate_count: duplicates.length,
    highest_similarity: duplicates.length > 0 ? (duplicates[0].score * 100).toFixed(1) : 0
  }
};

